SELECT SYSTEM$STREAM_HAS_DATA('SCH.MY_STREAM');
SELECT SYSTEM$USER_TASK_CANCEL_ONGOING_EXECUTIONS('MY_TASK');
SELECT SYSTEM$SHOW_STREAMLITS_IN_ACCOUNT(true, false);
SELECT
    A.COL_1,
    SYSTEM$CURRENT_USER_TASK_NAME() AS TASK_NAME,
    IFF(
        SYSTEM$CURRENT_USER_TASK_NAME() <> '',
        SYSTEM$CURRENT_USER_TASK_NAME(),
        CURRENT_USER()
    ) AS LOAD_USER
FROM (SELECT ROW_NUMBER() OVER (ORDER BY SEQ4()) AS COL_1 FROM TABLE(GENERATOR(ROWCOUNT => 5))) A;
